import{_ as n,H as s,f as l,i as t}from"./chunks/framework.BHvCMIhP.js";const h=JSON.parse('{"title":"操作系统系列写作计划","description":"","frontmatter":{},"headers":[],"relativePath":"../osLearning/00-写作计划.md","filePath":"../osLearning/00-写作计划.md","lastUpdated":1778496697000}'),e={name:"../osLearning/00-写作计划.md"};function i(o,a,p,r,d,c){return s(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="操作系统系列写作计划" tabindex="-1">操作系统系列写作计划 <a class="header-anchor" href="#操作系统系列写作计划" aria-label="Permalink to &quot;操作系统系列写作计划&quot;">​</a></h1><blockquote><p>来源:<code>未来系列规划.md</code> 第一类「补完整知识图」第四项,⭐⭐⭐⭐。 系统设计教了「<strong>怎么用工具</strong>」(Redis / MQ / 分库),OS 系列教了「<strong>这些工具底下到底在干嘛</strong>」——为什么 epoll 比 select 快、为什么 GC 会 Stop The World、为什么 Docker 看着像虚拟机其实是 namespace、为什么 false sharing 能让多线程程序变慢 10 倍。 <strong>看完这层,你看任何&quot;性能问题&quot;都能直接看到底</strong>——Java GC、Node 事件循环、Flutter Isolate、Go 协程、Rust async,全是这层往上长出来的。</p></blockquote><hr><h2 id="设计思路" tabindex="-1">设计思路 <a class="header-anchor" href="#设计思路" aria-label="Permalink to &quot;设计思路&quot;">​</a></h2><p>五层结构,从「机器视角」到「工程实战」:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>心智 + 基础(用户态 / 内核态 / 系统调用 / CPU)</span></span>
<span class="line"><span>   → 内存(虚拟内存 / 页表 / 分配 / 缓存)</span></span>
<span class="line"><span>   → 进程线程与并发(进程 / 线程 / IPC / 锁 / 调度 / 协程)</span></span>
<span class="line"><span>   → IO 与文件(VFS / IO 模型 / epoll / io_uring / 零拷贝)</span></span>
<span class="line"><span>   → 工程实战(信号 / 容器 / 性能工具 / eBPF)</span></span></code></pre></div><p><strong>这个系列不是 CSAPP 重写</strong>——CSAPP 太厚,重点偏教学;<strong>本系列偏&quot;工程师视角&quot;</strong>:每个概念都对应一个真实的&quot;性能问题或者 bug&quot;,学完能直接用在排错和调优。</p><p>不深入到内核源码,<strong>而是讲清楚&quot;用户态程序员能看到的内核行为&quot;</strong>——你写 Java / Go / Python,但调优时必须懂这些。<strong>95% 的性能瓶颈最终都落到 OS 这一层</strong>。</p><hr><h2 id="篇目-28-篇" tabindex="-1">篇目(28 篇) <a class="header-anchor" href="#篇目-28-篇" aria-label="Permalink to &quot;篇目(28 篇)&quot;">​</a></h2><h3 id="第一层-心智与基础-01-05" tabindex="-1">第一层:心智与基础(01-05) <a class="header-anchor" href="#第一层-心智与基础-01-05" aria-label="Permalink to &quot;第一层:心智与基础(01-05)&quot;">​</a></h3><ul><li>[x] 01 OS 总览(为什么程序员要懂 OS / 用户态内核态)</li><li>[x] 02 系统调用机制(syscall / glibc 包装 / 性能开销)</li><li>[x] 03 程序的生命周期(ELF / 编译 / 链接 / 加载 / 启动)</li><li>[x] 04 CPU 视角(寄存器 / 流水线 / 多核 / 缓存层级)</li><li>[x] 05 中断与异常(硬中断 / 软中断 / 系统调用三兄弟)</li></ul><h3 id="第二层-内存-06-10" tabindex="-1">第二层:内存(06-10) <a class="header-anchor" href="#第二层-内存-06-10" aria-label="Permalink to &quot;第二层:内存(06-10)&quot;">​</a></h3><ul><li>[x] 06 虚拟内存(为什么要虚拟 / 页表 / TLB / 缺页中断)</li><li>[x] 07 进程的内存布局(代码段 / 数据段 / 堆 / 栈 / 共享库)</li><li>[x] 08 内存分配(malloc / brk / mmap / glibc 内部)</li><li>[x] 09 内核内存与 slab(buddy / slab / 内核怎么管自己)</li><li>[x] 10 CPU 缓存与一致性(L1/L2/L3 / MESI / NUMA / false sharing)</li></ul><h3 id="第三层-进程线程与并发-11-17" tabindex="-1">第三层:进程线程与并发(11-17) <a class="header-anchor" href="#第三层-进程线程与并发-11-17" aria-label="Permalink to &quot;第三层:进程线程与并发(11-17)&quot;">​</a></h3><ul><li>[x] 11 进程(fork / exec / wait / 进程状态机)</li><li>[x] 12 线程模型(POSIX / 内核线程 / N:M 模型)</li><li>[x] 13 进程间通信(管道 / 共享内存 / 消息队列 / Unix Socket)</li><li>[x] 14 锁与原子操作(自旋 / 互斥 / 读写 / CAS / futex)</li><li>[x] 15 内存屏障与重排序(happens-before / volatile)</li><li>[x] 16 调度器(CFS / 优先级 / nice / 实时调度)</li><li>[x] 17 协程(用户态调度 / Go / asyncio / Rust async)</li></ul><h3 id="第四层-io-与文件-18-23" tabindex="-1">第四层:IO 与文件(18-23) <a class="header-anchor" href="#第四层-io-与文件-18-23" aria-label="Permalink to &quot;第四层:IO 与文件(18-23)&quot;">​</a></h3><ul><li>[x] 18 文件抽象(VFS / inode / fd / 一切皆文件)</li><li>[x] 19 文件系统(ext4 / XFS / btrfs / 写入路径)</li><li>[x] 20 IO 五种模型(阻塞 / 非阻塞 / 多路复用 / 信号 / 异步)</li><li>[x] 21 epoll 深入(红黑树 / 边缘触发 / 水平触发 / 惊群)</li><li>[x] 22 io_uring(Linux 5.1+ 的异步 IO 革命)</li><li>[x] 23 零拷贝(sendfile / splice / mmap / DMA)</li></ul><h3 id="第五层-工程实战-24-28" tabindex="-1">第五层:工程实战(24-28) <a class="header-anchor" href="#第五层-工程实战-24-28" aria-label="Permalink to &quot;第五层:工程实战(24-28)&quot;">​</a></h3><ul><li>[x] 24 信号(SIGSEGV / SIGCHLD / SIGTERM / 异步信号安全)</li><li>[x] 25 容器底层(namespace / cgroup / OverlayFS / runc)</li><li>[x] 26 性能工具(top / strace / perf / bpftrace / 火焰图)</li><li>[x] 27 eBPF(现代 Linux 的&quot;可编程内核&quot;)</li><li>[x] 28 OS 在云原生时代(总结 + Linux 内核演进 + 未来)</li></ul><hr><h2 id="与其他系列的边界" tabindex="-1">与其他系列的边界 <a class="header-anchor" href="#与其他系列的边界" aria-label="Permalink to &quot;与其他系列的边界&quot;">​</a></h2><table tabindex="0"><thead><tr><th>内容</th><th>已有系列</th><th>本系列</th></tr></thead><tbody><tr><td>网络协议(HTTP / TCP / UDP)</td><td>webLearning ✅</td><td>不重复,只讲 socket / IO 模型</td></tr><tr><td>GC 算法 / JVM</td><td>aiLearning(部分)/ flutter</td><td>互补,讲&quot;GC 怎么和 OS 协作&quot;</td></tr><tr><td>容器编排(K8s)</td><td>backendLearning/27-30 ✅</td><td>不重复,只讲容器底下的 namespace / cgroup</td></tr><tr><td>监控(Prometheus / 链路追踪)</td><td>backendLearning/33 / systemDesign/29 ✅</td><td>互补,讲&quot;OS 层的指标怎么解读&quot;</td></tr><tr><td>调度算法(分布式)</td><td>systemDesign / algorithm</td><td>不重复,只讲单机 OS 调度</td></tr><tr><td>锁(分布式锁)</td><td>backendLearning/20 ✅</td><td>不重复,只讲单机锁</td></tr></tbody></table><hr><h2 id="写作模板" tabindex="-1">写作模板 <a class="header-anchor" href="#写作模板" aria-label="Permalink to &quot;写作模板&quot;">​</a></h2><p>每篇遵守&quot;为什么 → 是什么 → 怎么用 → 何时不该用&quot;的四段式:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 为什么要有这个东西</span></span>
<span class="line"><span>   - 没它的世界长什么样</span></span>
<span class="line"><span>   - 加了它解决了什么问题</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 它是怎么实现的</span></span>
<span class="line"><span>   - 内核数据结构</span></span>
<span class="line"><span>   - 关键流程</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 用户态怎么用</span></span>
<span class="line"><span>   - C / Go / Java 视角的接口</span></span>
<span class="line"><span>   - 真实场景例子</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 何时不该用 / 坑在哪</span></span>
<span class="line"><span>   - 性能边界</span></span>
<span class="line"><span>   - 常见 bug</span></span>
<span class="line"><span>   - 替代方案</span></span></code></pre></div><p>不堆太多源码——<strong>只贴关键的内核数据结构和系统调用签名</strong>,让读者「知道这一层在干嘛」就够了。</p><hr><h2 id="节奏" tabindex="-1">节奏 <a class="header-anchor" href="#节奏" aria-label="Permalink to &quot;节奏&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>01-05  心智:看完知道&quot;OS 在程序员眼里到底是什么&quot;</span></span>
<span class="line"><span>06-10  内存:看完不会再被&quot;为什么我的程序占了这么多内存&quot;问倒</span></span>
<span class="line"><span>11-17  并发:**最值钱的一层**,Java / Go / Rust 并发模型全靠它</span></span>
<span class="line"><span>18-23  IO:**第二值钱**,所有&quot;性能调优&quot;最后都到这里</span></span>
<span class="line"><span>24-28  工程:用得到、面试问得到的硬通货</span></span></code></pre></div><p><strong>一个硬指标</strong>:看完 11-17 + 18-23 这 13 篇,你应该能在白板前讲清楚:</p><ul><li>&quot;为什么 Go 协程这么轻量,但密集 CPU 任务用线程更快&quot;</li><li>&quot;为什么我的服务 p99 抖动来自 GC,但不是所有 GC 都会 Stop The World&quot;</li><li>&quot;为什么把 epoll 换成 io_uring 能在某些场景快 30%&quot;</li></ul><p>能讲清楚一题这个系列就值了。</p><hr><h2 id="反对的写法" tabindex="-1">反对的写法 <a class="header-anchor" href="#反对的写法" aria-label="Permalink to &quot;反对的写法&quot;">​</a></h2><p>这个系列<strong>不写</strong>这些东西,见到了就是写错了:</p><ol><li>「Linux 内核 5.x 源码逐行分析」——不是教学,是工程师视角</li><li>「先讲个故事 / 个人情怀」——直接进重点</li><li>罗列 Linux 命令——只在工程实战(24-28)讲必备的</li><li>「这是面试常考」——读者来这里不是为了刷题,是为了真的看到底</li><li>抄 CSAPP / Linux Kernel Development——那两本书在那儿,这里只补它们没讲透的工程细节</li><li>不画图就讲 cache line / 虚拟内存——这些东西<strong>不画图永远讲不清楚</strong></li></ol>`,38)])])}const g=n(e,[["render",i]]);export{h as __pageData,g as default};
